from dataclasses import dataclass, field
from datetime import datetime, timedelta
from typing import Literal

Severity = Literal["P1", "P2", "P3", "P4"]
Status = Literal["open", "in_progress", "waiting_customer", "resolved", "escalated"]

@dataclass
class SupportTicket:
    ticket_id: str
    vendor: str
    severity: Severity
    title: str
    opened_at: datetime
    # SLA targets from contract (hours)
    response_sla_hours: float
    resolution_sla_hours: float

    first_response_at: datetime | None = None
    resolved_at: datetime | None = None
    status: Status = "open"
    escalated_tiers: list[str] = field(default_factory=list)

    @property
    def response_sla_deadline(self) -> datetime:
        return self.opened_at + timedelta(hours=self.response_sla_hours)

    @property
    def resolution_sla_deadline(self) -> datetime:
        return self.opened_at + timedelta(hours=self.resolution_sla_hours)

    def response_sla_breached(self) -> bool:
        if self.first_response_at:
            return self.first_response_at > self.response_sla_deadline
        return datetime.utcnow() > self.response_sla_deadline

    def resolution_sla_breached(self) -> bool:
        if self.resolved_at:
            return self.resolved_at > self.resolution_sla_deadline
        return datetime.utcnow() > self.resolution_sla_deadline

    def minutes_until_response_breach(self) -> float | None:
        if self.first_response_at:
            return None  # Already responded
        remaining = (self.response_sla_deadline - datetime.utcnow()).total_seconds() / 60
        return remaining

    def should_auto_escalate(self) -> str | None:
        """Return the escalation tier to trigger, or None."""
        if not self.first_response_at:
            return None
        elapsed_h = (datetime.utcnow() - self.opened_at).total_seconds() / 3600
        if self.severity == "P1":
            if elapsed_h >= 2 and "VP_ENG" not in self.escalated_tiers:
                return "VP_ENG"
            if elapsed_h >= 4 and "CTO" not in self.escalated_tiers:
                return "CTO"
        elif self.severity == "P2" and elapsed_h >= 8 and "SENIOR_ENG" not in self.escalated_tiers:
            return "SENIOR_ENG"
        return None
